// Accepts JSON fetch bodies AND text/plain sendBeacon bodies (raw string).
// Shapes: {kind:'submit-fallback', note, submission:{...}} | {kind:'draft', id, funnel, draft:{...}} | {kind:'submitted', submission:{...}}
const inp = $input.first().json;
let body = inp.body;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) { body = null; } }
if (!body || typeof body !== 'object') throw new Error('invalid body');
const p = body.submission || body.draft || {};
const id = String(body.id || p.id || '').trim();
if (!id) throw new Error('id required');
let kind = String(body.kind || '').trim();
if (!kind) kind = body.submission ? 'submit-fallback' : (body.draft ? 'draft' : 'unknown');
const answers = (p.answers && typeof p.answers === 'object') ? p.answers : (body.draft ? p : {});
const funnel = String(body.funnel || p.funnel || '').trim();
const first = String(p.first_name || answers.first_name || '').trim();
const last = String(p.last_name || answers.last_name || '').trim();
const email = String(p.email || answers.email || '').trim();
const now = new Date().toISOString();
const hasPayload = !!((body.submission && typeof body.submission === 'object') || (body.draft && typeof body.draft === 'object'));
return [{ json: {
  sub_id: id,
  kind,
  funnel,
  client_name: (first + ' ' + last).trim(),
  email,
  payload: hasPayload ? JSON.stringify(p) : '',
  note: String(body.note || ''),
  created_at: now,
  updated_at: now
} }];

